+                        .repeatForever()
+                        .withIntervalInSeconds(1))
+                .build();
+        quartz.scheduleJob(job, trigger);
+    }
+
+    @RegisterForReflection
+    public static class CountingJob implements Job {
+        @Override
+        public void execute(JobExecutionContext jobExecutionContext) {
+            try {
+                Thread.sleep(100l);
